"""Disk cache for fetched guide pages (markdown by URL/path)."""

import hashlib
from pathlib import Path

from .config import get_cache_dir


def _cache_key(url_or_path: str) -> str:
    """Return a safe filename for the cache (hash of normalized string)."""
    return hashlib.sha256(url_or_path.encode("utf-8")).hexdigest() + ".md"


def get_cached_markdown(url_or_path: str) -> str | None:
    """Return cached markdown for the given URL or path, or None if not cached."""
    cache_dir = get_cache_dir()
    path = cache_dir / _cache_key(url_or_path)
    if not path.exists():
        return None
    try:
        return path.read_text(encoding="utf-8")
    except OSError:
        return None


def set_cached_markdown(url_or_path: str, markdown: str) -> None:
    """Store markdown in the cache for the given URL or path."""
    cache_dir = get_cache_dir()
    cache_dir.mkdir(parents=True, exist_ok=True)
    path = cache_dir / _cache_key(url_or_path)
    path.write_text(markdown, encoding="utf-8")
